#ifndef MLA_PAGED_PREFILL_CAUSAL_H16_CKV512_KPE64_PS1_KERNEL_H_
#define MLA_PAGED_PREFILL_CAUSAL_H16_CKV512_KPE64_PS1_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <stdint.h>

#ifndef __CUDACC_RTC__
#include <torch/extension.h>
#endif

// Fixed constants from spec
static constexpr int kNumHeads = 16;
static constexpr int kHeadDimCkv = 512;
static constexpr int kHeadDimKpe = 64;
static constexpr int kPageSize = 1;

// Kernel launch API
void mla_paged_prefill_causal_h16_ckv512_kpe64_ps1_launch(
    const __nv_bfloat16* q_nope,   // [total_q, 16, 512]
    const __nv_bfloat16* q_pe,     // [total_q, 16, 64]
    const __nv_bfloat16* ckv_cache,// [num_pages, 1, 512]
    const __nv_bfloat16* kpe_cache,// [num_pages, 1, 64]
    const int32_t* qo_indptr,      // [len_indptr]
    const int32_t* kv_indptr,      // [len_indptr]
    const int32_t* kv_indices,     // [num_kv_indices]
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    __nv_bfloat16* output,         // [total_q, 16, 512]
    float* lse,                    // [total_q, 16] (log2sumexp)
    cudaStream_t stream);

#endif  // MLA_PAGED_PREFILL_CAUSAL_H16_CKV512_KPE64_PS1_KERNEL_H_

#include "kernel.h"
#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <math_constants.h>
#include <stdint.h>

#define CUDA_CHECK(ans) do { cudaError_t e = (ans); if (e != cudaSuccess) { printf("CUDA error %s:%d: %s\n", __FILE__, __LINE__, cudaGetErrorString(e)); } } while(0)

static __device__ __forceinline__ float bf16_to_f32(__nv_bfloat16 x) {
  return __bfloat162float(x);
}
static __device__ __forceinline__ __nv_bfloat16 f32_to_bf16(float x) {
  return __float2bfloat16_rn(x);
}

static __device__ __forceinline__ float warp_allreduce_sum(float v) {
  for (int offset = 16; offset > 0; offset >>= 1) v += __shfl_down_sync(0xffffffff, v, offset);
  return v;
}
static __device__ __forceinline__ float warp_allreduce_max(float v) {
  for (int offset = 16; offset > 0; offset >>= 1) v = fmaxf(v, __shfl_down_sync(0xffffffff, v, offset));
  return v;
}

// log2(exp2(a)+exp2(b)) stable merge with running m in log2-domain:
// m = max(m, x); s = s*2^(old_m-m)+2^(x-m)
struct Log2Acc {
  float m;   // max in log2 domain
  float s;   // sum of 2^(x-m)
};

static __device__ __forceinline__ void log2acc_init(Log2Acc &acc) {
  acc.m = -CUDART_INF_F;
  acc.s = 0.f;
}
static __device__ __forceinline__ void log2acc_update(Log2Acc &acc, float x_log2) {
  if (x_log2 == -CUDART_INF_F) return;
  if (acc.m == -CUDART_INF_F) {
    acc.m = x_log2;
    acc.s = 1.f;
    return;
  }
  float m_new = fmaxf(acc.m, x_log2);
  // rescale
  acc.s = acc.s * exp2f(acc.m - m_new) + exp2f(x_log2 - m_new);
  acc.m = m_new;
}
static __device__ __forceinline__ void log2acc_merge(Log2Acc &a, const Log2Acc &b) {
  if (b.m == -CUDART_INF_F) return;
  if (a.m == -CUDART_INF_F) { a = b; return; }
  float m_new = fmaxf(a.m, b.m);
  a.s = a.s * exp2f(a.m - m_new) + b.s * exp2f(b.m - m_new);
  a.m = m_new;
}
static __device__ __forceinline__ float log2acc_lse(const Log2Acc &acc) {
  if (acc.m == -CUDART_INF_F) return -CUDART_INF_F;
  return acc.m + log2f(acc.s);
}

// We compute in log2 domain to match output lse definition exactly.
// logits_scaled = logits * sm_scale (natural scale). Convert to log2 domain via /ln2.
static __device__ __forceinline__ float to_log2_domain(float x_natural) {
  constexpr float inv_ln2 = 1.4426950408889634f; // 1/ln(2)
  return x_natural * inv_ln2;
}

template<int WARPS_PER_BLOCK>
__global__ void mla_paged_prefill_causal_h16_ckv512_kpe64_ps1_kernel(
    const __nv_bfloat16* __restrict__ q_nope,    // [total_q,16,512]
    const __nv_bfloat16* __restrict__ q_pe,      // [total_q,16,64]
    const __nv_bfloat16* __restrict__ ckv_cache, // [num_pages,1,512]
    const __nv_bfloat16* __restrict__ kpe_cache, // [num_pages,1,64]
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    const int32_t* __restrict__ kv_indices,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    __nv_bfloat16* __restrict__ output,          // [total_q,16,512]
    float* __restrict__ lse)                    // [total_q,16]
{
  // Mapping:
  // blockIdx.x -> query token index qi in [0,total_q)
  // Each warp handles one head (up to WARPS_PER_BLOCK heads per block).
  const int qi = (int)blockIdx.x;
  if (qi >= total_q) return;

  const int tid = (int)threadIdx.x;
  const int warp_id = tid >> 5;
  const int lane = tid & 31;

  if (warp_id >= WARPS_PER_BLOCK) return;
  const int head = warp_id; // since num_heads=16, choose WARPS_PER_BLOCK=16
  if (head >= kNumHeads) return;

  // Find batch b such that qo_indptr[b] <= qi < qo_indptr[b+1]
  // len_indptr = batch_size+1, small enough to binary search on GPU.
  int lo = 0, hi = len_indptr - 2;
  int b = 0;
  while (lo <= hi) {
    int mid = (lo + hi) >> 1;
    int32_t qs = __ldg(qo_indptr + mid);
    int32_t qe = __ldg(qo_indptr + mid + 1);
    if (qi < qs) hi = mid - 1;
    else if (qi >= qe) lo = mid + 1;
    else { b = mid; break; }
  }

  const int32_t q_start = __ldg(qo_indptr + b);
  const int32_t q_end   = __ldg(qo_indptr + b + 1);
  const int32_t page_beg = __ldg(kv_indptr + b);
  const int32_t page_end = __ldg(kv_indptr + b + 1);

  if (!(q_start < q_end && page_beg < page_end)) {
    // write defaults
    if (lane == 0) lse[qi * kNumHeads + head] = -CUDART_INF_F;
    // output already assumed uninitialized; set to 0
    for (int d = lane; d < kHeadDimCkv; d += 32) {
      output[(qi * kNumHeads + head) * kHeadDimCkv + d] = f32_to_bf16(0.f);
    }
    return;
  }

  const int q_len = (int)(q_end - q_start);
  const int kv_len = (int)(page_end - page_beg);
  const int i = (int)(qi - q_start);
  const int prefix_len = kv_len - q_len;
  const int query_abs_pos = prefix_len + i; // causal boundary: allow k<=query_abs_pos

  // Pointers to this query/head
  const __nv_bfloat16* qn_ptr = q_nope + ((qi * kNumHeads + head) * kHeadDimCkv);
  const __nv_bfloat16* qp_ptr = q_pe   + ((qi * kNumHeads + head) * kHeadDimKpe);

  // 2-pass streaming softmax:
  // pass1: compute log2-LSE of masked logits (scaled)
  // pass2: accumulate output = sum softmax * Kc

  // PASS1
  Log2Acc acc;
  log2acc_init(acc);

  // iterate keys
  for (int kj = 0; kj < kv_len; ++kj) {
    const int k_abs = kj;
    if (k_abs > query_abs_pos) {
      continue; // masked
    }
    const int32_t page_idx = __ldg(kv_indices + (page_beg + kj));

    // dot(qn, Kc) + dot(qp,Kp)
    float partial = 0.f;

    // CKV 512
    // each lane processes strided dims
    for (int d = lane; d < kHeadDimCkv; d += 32) {
      // cache layout: [num_pages,1,dim], page_size=1
      const __nv_bfloat16 k = __ldg(ckv_cache + (page_idx * kHeadDimCkv + d));
      const __nv_bfloat16 q = __ldg(qn_ptr + d);
      partial += bf16_to_f32(q) * bf16_to_f32(k);
    }
    // KPE 64
    for (int d = lane; d < kHeadDimKpe; d += 32) {
      const __nv_bfloat16 k = __ldg(kpe_cache + (page_idx * kHeadDimKpe + d));
      const __nv_bfloat16 q = __ldg(qp_ptr + d);
      partial += bf16_to_f32(q) * bf16_to_f32(k);
    }
    float dot = warp_allreduce_sum(partial);
    if (lane == 0) {
      float scaled = dot * sm_scale;
      float x_log2 = to_log2_domain(scaled);
      log2acc_update(acc, x_log2);
    }
  }

  // Broadcast acc.m and acc.s from lane0 to all lanes
  float m_log2 = __shfl_sync(0xffffffff, acc.m, 0);
  float s_sum  = __shfl_sync(0xffffffff, acc.s, 0);
  float lse_log2 = (m_log2 == -CUDART_INF_F) ? -CUDART_INF_F : (m_log2 + log2f(s_sum));
  if (lane == 0) {
    lse[qi * kNumHeads + head] = lse_log2;
  }

  // PASS2: out_d = sum_j softmax_j * Kc_j[d]
  // softmax_j = exp(logits_scaled - lse_nat) but we stay in base2:
  // weight = 2^(x_log2 - lse_log2)
  // since lse_log2 = log2(sum 2^x)
  // weight = 2^(x - lse_log2)
  for (int d = lane; d < kHeadDimCkv; d += 32) {
    float out = 0.f;
    for (int kj = 0; kj < kv_len; ++kj) {
      if (kj > query_abs_pos) continue;
      const int32_t page_idx = __ldg(kv_indices + (page_beg + kj));

      float partial = 0.f;
      // recompute dot (yes; memory-bound but no kv tiling possible with kv_len dynamic and huge dim)
      for (int dd = lane; dd < kHeadDimCkv; dd += 32) {
        const __nv_bfloat16 k = __ldg(ckv_cache + (page_idx * kHeadDimCkv + dd));
        const __nv_bfloat16 q = __ldg(qn_ptr + dd);
        partial += bf16_to_f32(q) * bf16_to_f32(k);
      }
      for (int dd = lane; dd < kHeadDimKpe; dd += 32) {
        const __nv_bfloat16 k = __ldg(kpe_cache + (page_idx * kHeadDimKpe + dd));
        const __nv_bfloat16 q = __ldg(qp_ptr + dd);
        partial += bf16_to_f32(q) * bf16_to_f32(k);
      }
      float dot = warp_allreduce_sum(partial);
      float x_log2 = to_log2_domain(dot * sm_scale);
      float w = exp2f(x_log2 - lse_log2);

      // now lane computes its output dimension d: multiply by Kc[d]
      const __nv_bfloat16 kc = __ldg(ckv_cache + (page_idx * kHeadDimCkv + d));
      out += w * bf16_to_f32(kc);
    }
    output[(qi * kNumHeads + head) * kHeadDimCkv + d] = f32_to_bf16(out);
  }
}

void mla_paged_prefill_causal_h16_ckv512_kpe64_ps1_launch(
    const __nv_bfloat16* q_nope,
    const __nv_bfloat16* q_pe,
    const __nv_bfloat16* ckv_cache,
    const __nv_bfloat16* kpe_cache,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    const int32_t* kv_indices,
    int32_t len_indptr,
    int32_t total_q,
    float sm_scale,
    __nv_bfloat16* output,
    float* lse,
    cudaStream_t stream)
{
  // One block per query token; 16 warps per block => 512 threads
  constexpr int WARPS = 16;
  constexpr int THREADS = WARPS * 32;
  dim3 block(THREADS);
  dim3 grid(total_q);
  mla_paged_prefill_causal_h16_ckv512_kpe64_ps1_kernel<WARPS><<<grid, block, 0, stream>>>(
      q_nope, q_pe, ckv_cache, kpe_cache, qo_indptr, kv_indptr, kv_indices,
      len_indptr, total_q, sm_scale, output, lse);
  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda.h>
#include <cuda_runtime.h>

#include "kernel.h"

static void check_cuda(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
}

static void check_dtype(const torch::Tensor& t, c10::ScalarType dt, const char* name) {
  TORCH_CHECK(t.scalar_type() == dt, name, " must have dtype ", c10::toString(dt),
              ", got ", c10::toString(t.scalar_type()));
}

std::vector<torch::Tensor> run(
    torch::Tensor q_nope,     // bf16 [total_q,16,512]
    torch::Tensor q_pe,       // bf16 [total_q,16,64]
    torch::Tensor ckv_cache,  // bf16 [num_pages,1,512]
    torch::Tensor kpe_cache,  // bf16 [num_pages,1,64]
    torch::Tensor qo_indptr,  // int32 [len_indptr]
    torch::Tensor kv_indptr,  // int32 [len_indptr]
    torch::Tensor kv_indices, // int32 [num_kv_indices]
    c10::optional<double> sm_scale_opt
) {
  check_cuda(q_nope, "q_nope");
  check_cuda(q_pe, "q_pe");
  check_cuda(ckv_cache, "ckv_cache");
  check_cuda(kpe_cache, "kpe_cache");
  check_cuda(qo_indptr, "qo_indptr");
  check_cuda(kv_indptr, "kv_indptr");
  check_cuda(kv_indices, "kv_indices");

  check_dtype(q_nope, c10::kBFloat16, "q_nope");
  check_dtype(q_pe, c10::kBFloat16, "q_pe");
  check_dtype(ckv_cache, c10::kBFloat16, "ckv_cache");
  check_dtype(kpe_cache, c10::kBFloat16, "kpe_cache");
  check_dtype(qo_indptr, c10::kInt, "qo_indptr");
  check_dtype(kv_indptr, c10::kInt, "kv_indptr");
  check_dtype(kv_indices, c10::kInt, "kv_indices");

  TORCH_CHECK(q_nope.dim() == 3, "q_nope must be [total_q,16,512]");
  TORCH_CHECK(q_pe.dim() == 3, "q_pe must be [total_q,16,64]");
  TORCH_CHECK(ckv_cache.dim() == 3, "ckv_cache must be [num_pages,1,512]");
  TORCH_CHECK(kpe_cache.dim() == 3, "kpe_cache must be [num_pages,1,64]");
  TORCH_CHECK(qo_indptr.dim() == 1, "qo_indptr must be 1D");
  TORCH_CHECK(kv_indptr.dim() == 1, "kv_indptr must be 1D");
  TORCH_CHECK(kv_indices.dim() == 1, "kv_indices must be 1D");

  const auto total_q = (int32_t)q_nope.size(0);
  TORCH_CHECK(q_nope.size(1) == kNumHeads && q_nope.size(2) == kHeadDimCkv,
              "q_nope shape must be [total_q,16,512]");
  TORCH_CHECK(q_pe.size(0) == total_q && q_pe.size(1) == kNumHeads && q_pe.size(2) == kHeadDimKpe,
              "q_pe shape must be [total_q,16,64]");
  TORCH_CHECK(ckv_cache.size(1) == kPageSize && ckv_cache.size(2) == kHeadDimCkv,
              "ckv_cache shape must be [num_pages,1,512]");
  TORCH_CHECK(kpe_cache.size(1) == kPageSize && kpe_cache.size(2) == kHeadDimKpe,
              "kpe_cache shape must be [num_pages,1,64]");

  TORCH_CHECK(qo_indptr.size(0) == kv_indptr.size(0),
              "qo_indptr and kv_indptr must have same length");
  const int32_t len_indptr = (int32_t)qo_indptr.size(0);
  TORCH_CHECK(len_indptr >= 2, "len_indptr must be >= 2");
  TORCH_CHECK(qo_indptr.scalar_type() == c10::kInt, "qo_indptr must be int32");
  TORCH_CHECK(kv_indptr.scalar_type() == c10::kInt, "kv_indptr must be int32");

  // Validate constraints: total_q == qo_indptr[-1], num_kv_indices == kv_indptr[-1]
  // (Pull small scalars to CPU)
  int32_t qo_last = qo_indptr.index({len_indptr - 1}).cpu().item<int32_t>();
  TORCH_CHECK(qo_last == total_q, "Constraint violated: total_q must equal qo_indptr[-1]");
  int32_t kv_last = kv_indptr.index({len_indptr - 1}).cpu().item<int32_t>();
  TORCH_CHECK(kv_last == (int32_t)kv_indices.size(0),
              "Constraint violated: num_kv_indices must equal kv_indptr[-1]");

  double default_sm = 1.0 / std::sqrt(192.0);
  float sm_scale = (float)(sm_scale_opt.has_value() ? sm_scale_opt.value() : default_sm);

  auto out = torch::empty({total_q, kNumHeads, kHeadDimCkv},
                          torch::TensorOptions().device(q_nope.device()).dtype(torch::kBFloat16));
  auto lse = torch::empty({total_q, kNumHeads},
                          torch::TensorOptions().device(q_nope.device()).dtype(torch::kFloat32));

  // Flatten cache page_size=1 for kernel addressing ([num_pages,dim])
  auto ckv_flat = ckv_cache.view({ckv_cache.size(0), kHeadDimCkv}).contiguous();
  auto kpe_flat = kpe_cache.view({kpe_cache.size(0), kHeadDimKpe}).contiguous();

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  mla_paged_prefill_causal_h16_ckv512_kpe64_ps1_launch(
      (const __nv_bfloat16*)q_nope.data_ptr<at::BFloat16>(),
      (const __nv_bfloat16*)q_pe.data_ptr<at::BFloat16>(),
      (const __nv_bfloat16*)ckv_flat.data_ptr<at::BFloat16>(),
      (const __nv_bfloat16*)kpe_flat.data_ptr<at::BFloat16>(),
      (const int32_t*)qo_indptr.data_ptr<int32_t>(),
      (const int32_t*)kv_indptr.data_ptr<int32_t>(),
      (const int32_t*)kv_indices.data_ptr<int32_t>(),
      len_indptr,
      total_q,
      sm_scale,
      (__nv_bfloat16*)out.data_ptr<at::BFloat16>(),
      (float*)lse.data_ptr<float>(),
      stream);

  // Ensure completion and surface errors
  C10_CUDA_CHECK(cudaGetLastError());
  C10_CUDA_CHECK(cudaDeviceSynchronize());

  return {out, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run,
        "mla_paged_prefill_causal_h16_ckv512_kpe64_ps1 (CUDA)",
        py::arg("q_nope"),
        py::arg("q_pe"),
        py::arg("ckv_cache"),
        py::arg("kpe_cache"),
        py::arg("qo_indptr"),
        py::arg("kv_indptr"),
        py::arg("kv_indices"),
        py::arg("sm_scale") = py::none());
}
